  public void updateRequiredWorkflowAttributesForTestAccount(Workflow workflow, String appid, String appName, String requesterName) {

    import sailpoint.object.Attributes;
    import java.util.HashMap;
    import java.util.Date;
    import java.util.List;
    import java.text.DateFormat;
    import java.text.SimpleDateFormat;

    import sailpoint.tools.Util;

    import java.text.DateFormat;
    import java.text.SimpleDateFormat;

    import sailpoint.object.Link;
    import sailpoint.object.Custom;
    import sailpoint.object.Identity;
    import sailpoint.object.Application;

    import sailpoint.api.IdentityService;

    import org.apache.log4j.Level;
    import org.apache.log4j.Logger;

    Logger logger = Logger.getLogger(loggerClass);

    String firstName = null;
    String lastName = null;

    if (Util.isNotNullOrEmpty(appid) && Util.isNotNullOrEmpty(appName)) {
      firstName = appName;
      lastName = appid;
      workflow.put("firstName", appName);
      workflow.put("lastName", appid);
    }

    Identity requester = context.getObjectByName(Identity.class, requesterName); 
    String requesterEmail = requester.getEmail() != null ? requester.getEmail() : null;
    String requesterFullName = requester.getLastname() + ", " + requester.getFirstname(); 
    String requestedBy = requesterFullName + "(" + requesterName + ")";

    log.error("Workflow_VSNT_Test_Account_Migration: ---------------requester -----------------" + requester);
    log.error("Workflow_VSNT_Test_Account_Migration: ---------------requesterEmail -----------------" + requesterEmail);
    log.error("Workflow_VSNT_Test_Account_Migration: ---------------requesterFullName -----------------" + requesterFullName);
    log.error("Workflow_VSNT_Test_Account_Migration: ---------------requestedBy -----------------" + requestedBy);

    workflow.put("requesterEmail", requesterEmail);
    workflow.put("requesterFullName", requesterFullName);
    workflow.put("requestedBy", requestedBy);

    String requestee = workflow.get("requestee");

    log.error("Workflow_VSNT_Test_Account_Migration: ---------------requestee -----------------" + requestee);

    if (Util.isNotNullOrEmpty(requestee)) {
      Identity identityObject = context.getObjectByName(Identity.class, requestee);
      String requesteeEmail = identityObject.getEmail() != null ? identityObject.getEmail() : null;
      String requesteeFullName = identityObject.getLastname() + ", " + identityObject.getFirstname(); 
      String requestedfor = requesteeFullName + "(" + requestee + ")";

      log.error("Workflow_VSNT_Test_Account_Migration: ---------------identityObject -----------------" + identityObject);
      log.error("Workflow_VSNT_Test_Account_Migration: ---------------requesteeEmail -----------------" + requesteeEmail);
      log.error("Workflow_VSNT_Test_Account_Migration: ---------------requesteeFullName -----------------" + requesteeFullName);
      log.error("Workflow_VSNT_Test_Account_Migration: ---------------requestedfor -----------------" + requestedfor);

      if (Util.isNotNullOrEmpty(requesteeEmail)) {
        workflow.put("requesteeEmail", requesteeEmail);
      } else {

        IdentityService idService = new IdentityService(context);
        List<Link> links = idService.getLinks(identityObject, context.getObjectByName(Application.class, "Application_VSNT_HR"));
        Link link = Util.nullSafeSize(links) > 0 && links.get(0) != null ? links.get(0) : null;

        String email = null;
        if (link != null) {
          email = link.getAttribute("C001_EMAIL");
        }
        log.debug("--------------requesteeEmail_insideloop --------------" + email);
        if (null != email) {
          workflow.put("requesteeEmail", email);
        } else {
          Custom nbcuemailaddress = context.getObjectByName(Custom.class, "Custom_VSNT_Mail_box_Name");
          String nbcumailbox = nbcuemailaddress.get("emailaddress");
          workflow.put("requesteeEmail", nbcumailbox);
        }
      }
      workflow.put("requesteeFullName", requesteeFullName);
      workflow.put("requestedfor", requestedfor);
    }

    String managersso = workflow.get("managersso");

    if (Util.isNotNullOrEmpty(managersso)) {

      log.error("Workflow_VSNT_ServceAccount_Creation: --------------Before   managerDetailsMap --------------");
      Map managerDetailsMap = createManagerDetailsMapForTestAccount(workflow, managersso);
      log.error("Workflow_VSNT_ServceAccount_Creation: --------------managerDetailsMap --------------"+managerDetailsMap);
      workflow.put("managerDetailsMap", managerDetailsMap);


      Identity managerObject = context.getObjectByName(Identity.class, managersso);
      String managerName = managerObject.getName();
      String managerFullName = managerObject.getLastname() + ", " + managerObject.getFirstname();
      String managerEmail = managerObject.getEmail();
      String managerFullSSO = managerFullName + "(" + supervisorid + ")";

      workflow.put("managerName", managerName);
      workflow.put("managerEmail", managerEmail);
      workflow.put("managerFullName", managerFullName);
      workflow.put("managerFullSSO", managerFullSSO);

      String identityFullName = lastname + ", " + firstname;
      workflow.put("identityFullName", identityFullName);

      String drupalToSailPointRequestDate = "";
      DateFormat dateFormat = new SimpleDateFormat("dd-MMM-yyyy HH:mm");
      Date date = new Date();
      drupalToSailPointRequestDate = dateFormat.format(date);

      workflow.put("drupalToSailPointRequestDate", drupalToSailPointRequestDate);

      String reminderCCAddress="";
      if (null != requesterEmail) {
        reminderCCAddress = reminderCCAddress + "," + requesterEmail;
      } else {
        Custom nbcuemailaddress = context.getObjectByName(Custom.class, "Custom_VSNT_Mail_box_Name");
        String nbcumailbox = nbcuemailaddress.get("emailaddress");
        reminderCCAddress = reminderCCAddress + nbcumailbox;	
      }
      if (null != requesteeEmail) {
        reminderCCAddress = reminderCCAddress + "," + requesteeEmail;
      }

      workflow.put("reminderCCAddress", reminderCCAddress);

      String rejectionToAddress = "";
      if (null != requesterEmail) {
        rejectionToAddress=rejectionToAddress + "," + requesterEmail;
      }
      if (null != managerEmail) {
        rejectionToAddress = managerEmail + "," + rejectionToAddress;
      }
      workflow.put("rejectionToAddress", rejectionToAddress);

    }
    //setting flag as false for future use
    String provFlag = "false";
    String apprFlag = "false";
    workflow.put("provFlag", provFlag);
    workflow.put("apprFlag", apprFlag);

    log.error("Workflow_VSNT_Test_Account_Migration: End method:::");

  }


  public ProvisioningPlan createNDIProvPlanForTestAccount(Workflow workflow) {

