    acctRequest.add(new AttributeRequest("hreffectiveenddate", ProvisioningPlan.Operation.Set, endDate));
    acctRequest.add(new AttributeRequest("hreffectivestartdate", ProvisioningPlan.Operation.Set, startDate));
    acctRequest.add(new AttributeRequest("hrpersontypeid", ProvisioningPlan.Operation.Set, "99996"));
    acctRequest.add(new AttributeRequest("hrpole", ProvisioningPlan.Operation.Set, "11I"));
    acctRequest.add(new AttributeRequest("hrsupervisorid", ProvisioningPlan.Operation.Set, mngrDisplayName));
    acctRequest.add(new AttributeRequest("hrusersubpersontype", ProvisioningPlan.Operation.Set, "Test"));
    acctRequest.add(new AttributeRequest("hrfullname", ProvisioningPlan.Operation.Set, lastname + ", " + firstname));        

    if(mngrbusinessUnitId != null)
      acctRequest.add(new AttributeRequest("hrbusinessunitid", ProvisioningPlan.Operation.Set, mngrbusinessUnitId));
    acctRequest.add(new AttributeRequest("locationid", "IDMFUNCTIONAL"));
    if(mngrorgid != null)
      acctRequest.add(new AttributeRequest("orgid", ProvisioningPlan.Operation.Set, mngrorgid));
    acctRequest.add(new AttributeRequest("persontypeid", ProvisioningPlan.Operation.Set, "99996"));

    acctRequest.add(new AttributeRequest("ownerid", ProvisioningPlan.Operation.Set, membername));
    if(mngrparentbusinessUnitId != null)
      acctRequest.add(new AttributeRequest("hrparentbusinessunitid", ProvisioningPlan.Operation.Set, mngrparentbusinessUnitId));
    acctRequest.add(new AttributeRequest("oraclehrid", ProvisioningPlan.Operation.Set, NewID));
    acctRequest.add(new AttributeRequest("ssostatus", ProvisioningPlan.Operation.Set, "U"));

    List accReqList = new ArrayList();
    accReqList.add(acctRequest);
    planNDI.setAccountRequests(accReqList);
    workflow.put("planNDI", planNDI);
    log.error("plan Create_NDI_Provision_Plan " + planNDI);
    return planNDI;
  }



  /** 
  * This method is used to calculate the date based on Current time Zone
  * @param dateValue
  * @param timeZone
  * @return
  */
  public Date getTimezoneCorrectedDate(Date dateValue, String timeZone) {

    log.error("Start getTimezoneCorrectedDate");
    Instant instant = Instant.ofEpochMilli(dateValue.getTime());
    ZoneId userTimeZone = TimeZone.getTimeZone(timeZone).toZoneId();
    ZonedDateTime zonedDateTime = instant.atZone(userTimeZone);
    ZoneId serverTimeZone = TimeZone.getDefault().toZoneId();
    LocalDate timelessDate = LocalDate.of(zonedDateTime.getYear(), zonedDateTime.getMonth(), zonedDateTime.getDayOfMonth());
    Date correctedDate = new Date(timelessDate.atStartOfDay(serverTimeZone).toInstant().toEpochMilli());
    log.error("correctedDate is: " + correctedDate);
    log.error("Leave getTimezoneCorrectedDate");
    return correctedDate;
  }


  /**
     * create the confirmation form 
     * @param displayForm - the form filled by the requester
     * @param formModel - contains key-value pair
     * @return Confirmation Form object
     */
  public Form getConfirmationForm(String displayFormName, Map formModel) {
    logger.debug("Started Method : getConfirmationForm");
    Form confirmationForm = null;
    List displayFormFields = null;
    String displayName = null;
    String name = null;
    String type = null;
    String displayType = null;
    int span = 1;
    boolean isMulti;
    Form displayForm =context.getObjectByName(Form.class,displayFormName);

    if(displayForm!=null && formModel!=null) {
      Map customFormMap = formModel.get("customVSNTWrapperForms").get(formModel.get("useCase")).get(formModel.get("operation"));
      if(customFormMap!=null && customFormMap.get("section")!=null && customFormMap.get("useCaseName")!=null && formModel.get("customVSNTWrapperForms").get("buttons")!=null) {
        logger.debug("inside if");
        confirmationForm = new Form();
        Section confirmationFormSection = new Section();
        confirmationFormSection.setColumns(2);
        confirmationForm.setTitle("Confirmation Form");
        List formSectionNames = customFormMap.get("section"); 
        String useCaseName = customFormMap.get("useCaseName");
        Map buttons =  formModel.get("customVSNTWrapperForms").get("buttons");
        useCaseName = useCaseName + " Review";    
        confirmationFormSection.setLabel(useCaseName);
        for(String section:formSectionNames) {
          displayFormFields = displayForm.getSection(section).getFields();
          if(displayFormFields!=null) {
            for (Field displayFormField : displayFormFields) {
              if(formModel.get(displayFormField.getName())!=null){
                Field confirmationFormField = new Field();
                displayName = displayFormField.getDisplayName();
                name = displayFormField.getName();
                type = displayFormField.getType();
                displayType = displayFormField.getDisplayType();
                span = displayFormField.getColumnSpan();
                isMulti = displayFormField.isMulti();
                if(isMulti) {
                  confirmationFormField.setMulti(isMulti);
                }
                confirmationFormField.setType(type);
                confirmationFormField.setDisplayName(displayName);
                confirmationFormField.setName(name);
                confirmationFormField.setColumnSpan(span);
                confirmationFormField.setDisplayType(displayType);
                confirmationFormField.setReadOnly(true);
                confirmationFormSection.add(confirmationFormField);
              }
            }
          }
        }
        for (Map.Entry entry : buttons.entrySet()) {
          Button button = new Button(entry.getKey(),entry.getValue());
          confirmationForm.add(button);
        }
        confirmationForm.add(confirmationFormSection);
      }
    }
    logger.debug("Method Exit : getConfirmationForm");
    return confirmationForm;
  }

  public Map createManagerDetailsMapForTestAccount(Workflow workflow, String managersso) {

    import sailpoint.object.Application;
