    import sailpoint.object.Link;
    import java.util.HashMap;
    import java.util.Map;
    import sailpoint.object.Custom;
    import java.util.ArrayList;

    import sailpoint.object.*;

    Boolean linkFlag= false;
    log.error("Starting : createManagerDetailsMapForTestAccount ");

    Identity managerObject = context.getObjectByName(Identity.class,managersso);
    Map managerDetailsMap = null;
    if (null!=managerObject){
      managerDetailsMap = new HashMap();
      managerDetailsMap.put("managerName", managerObject.getName());
      managerDetailsMap.put("mngrFirstName", managerObject.getFirstname());
      managerDetailsMap.put("mngrlastname", managerObject.getLastname());
      managerDetailsMap.put("mngrname", managerObject.getAttribute("userName"));
      managerDetailsMap.put("mngrDisplayName", managerObject.getAttribute("displayName"));
      managerDetailsMap.put("mngrWorkCountry", managerObject.getAttribute("workCountry"));
      log.error("Starting : 1 ");

      String managerEmail = managerObject.getEmail();
      (managerEmail != null ? managerEmail : "idm.auto-mailer@nbcuni.com");
      managerDetailsMap.put("managerEmail", managerEmail);
      managerDetailsMap.put("managerFullName", managerObject.getLastname()+", "+managerObject.getFirstname());
      managerDetailsMap.put("managerFullNameSSO",managerFullName + "(" + managersso + ")");
      log.error("Starting : 2 ");
      Link links = managerObject.getLink(context.getObjectByName(Application.class, "Application_VSNT_HR"));
      log.error("Starting : 3 ");
      if(links != null ){
        log.error("Starting : 4 ");
        Map attributes= new HashMap();
        attributes = links.getAttributes();
        if(attributes != null)   {

          if (attributes.get("C001_DEPARTMENT_NAME") != null)
            managerDetailsMap.put("mngrdepartment", attributes.get("C001_DEPARTMENT_NAME").toString());
          log.error("Starting : 5 ");
          if (attributes.get("C001_ORGID") != null)
            managerDetailsMap.put("mngrorgid",attributes.get("C001_ORGID").toString());
          log.error("Starting : 6 ");
          if (attributes.get("C001_BUSINESS_UNIT_ID") != null)
            managerDetailsMap.put("mngrbusinessUnitId",attributes.get("C001_BUSINESS_UNIT_ID").toString());
          else{
            Custom customBusinessID = context.getObjectByName(Custom.class, "Custom_VSNT_ContractorBusinessID");
            log.error("Starting : 7 ");
            Attributes attributes = customBusinessID.getAttributes();
            Map businessIDMap=new HashMap();
            String businessId = null;
            businessIDMap = attributes.getMap();
            log.error("Starting : 8 ");
            if((businessIDMap.get(managerOrgSegmentID)) != null)
              businessId = businessIDMap.get(managerOrgSegmentID).toString();
            log.error("Starting : 9 ");
            if(businessId != null){
              managerDetailsMap.put("mngrbusinessUnitId",businessId.toString());
              log.error("Workflow_NBCU_TestAccount_Creation: businessId Test Account Creation "+businessId.toString());
            }
            log.error("Starting : 10 ");
          }
          log.error("Starting : 1 ");
          if (attributes.get("C001_PARENT_BIZ_ID") != null)
            managerDetailsMap.put("mngrparentbusinessUnitId",attributes.get("C001_PARENT_BIZ_ID").toString());
          else{
            log.error("Starting : 11 ");
            Custom customBusinessID = context.getObjectByName(Custom.class, "Custom_VSNT_ContractorBusinessID");
            Map businessIDMap=new HashMap();
            Attributes attributes = customBusinessID.getAttributes();
            String parentBusinessId = null;
            businessIDMap = attributes.getMap();
            log.error("Starting : 12 ");
            if((businessIDMap.get(managerOrgSegmentID))!= null)
              parentBusinessId = businessIDMap.get(managerOrgSegmentID).toString();
            if(parentBusinessId != null){
              managerDetailsMap.put("mngrparentbusinessUnitId",parentBusinessId.toString());
              log.error("Workflow_NBCU_TestAccount_Creation: parentBusinessId Test Account Creation "+parentBusinessId.toString());
            }
          }
        }
      }
    }
    return managerDetailsMap;
  }
